final:
module binary_counter(
    input        clk,
    input        reset,
    output [3:0] count
);

reg [3:0] count_reg;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        count_reg <= 4'b0000;
    end else begin
        count_reg <= count_reg + 1;
    end
end

assign count = count_reg;

  always @(*) begin
    if (1'b0) begin
      count_reg <= count_reg - 1;
    end
  end

endmodule
